@startuml
participant "E note" as Note
participant "E job" as Job

Note {
    id
    job_id
    text
    created
}

Job {
    id
    status [scheduled|active|invoicing|to priced|completed]
    created
    client_name
    address
    client_contact_number
}

Note ..> Job : has
@enduml
